// Curseur
const cursor = document.getElementById('cursor');
const cursorRing = document.getElementById('cursorRing');
let mouseX=0,mouseY=0,ringX=0,ringY=0;
document.addEventListener('mousemove',e=>{mouseX=e.clientX;mouseY=e.clientY;cursor.style.left=mouseX+'px';cursor.style.top=mouseY+'px'});
(function animRing(){ringX+=(mouseX-ringX)*.12;ringY+=(mouseY-ringY)*.12;cursorRing.style.left=ringX+'px';cursorRing.style.top=ringY+'px';requestAnimationFrame(animRing)})();
document.querySelectorAll('button,a,input,label').forEach(el=>{
  el.addEventListener('mouseenter',()=>{cursorRing.style.transform='translate(-50%,-50%) scale(1.5)';cursorRing.style.opacity='1'});
  el.addEventListener('mouseleave',()=>{cursorRing.style.transform='translate(-50%,-50%) scale(1)';cursorRing.style.opacity='.5'});
});

// Configurateur 3D
const IMGS = {
  tie:    ["","",""],
  jacket: ["","",""],
  pants:  ["","",""]
};

const N=3, R=window.innerWidth<=480?95:135;
const st={tie:0,jacket:0,pants:0};
const ang={tie:0,jacket:0,pants:0};

function build(piece){
  const ring=document.getElementById('ring-'+piece);
  ring.innerHTML='';
  for(let i=0;i<N;i++){
    const div=document.createElement('div');
    div.className='rslide';
    div.style.transform=`translateX(-50%) rotateY(${(360/N)*i}deg) translateZ(${R}px)`;
    const img=document.createElement('img');
    img.src='data:image/png;base64,'+IMGS[piece][i];
    div.appendChild(img);
    ring.appendChild(div);
  }
}

function updateOpacities(piece) {
  const ring = document.getElementById('ring-' + piece);
  const slides = ring.querySelectorAll('.rslide');
  slides.forEach((slide, i) => {
    // Angle of this slide relative to front (0 = facing viewer)
    const slideDeg = (360 / N) * i;
    // Current ring rotation
    const ringDeg  = ang[piece];
    // Effective angle mod 360
    let eff = (slideDeg + ringDeg) % 360;
    if (eff < 0) eff += 360;
    // eff=0 → front (opacity 1), eff=120 or 240 → side (opacity 0.22)
    // Use cosine: cos(0)=1, cos(120°)=-0.5 → map to [0.18, 1]
    const rad = eff * Math.PI / 180;
    const cos = Math.cos(rad);
    // map cos [-1,1] → [0.12, 1]
    const opacity = 0.12 + (cos + 1) / 2 * 0.88;
    // scale: front=1, sides=0.75
    const scale = 0.75 + (cos + 1) / 2 * 0.25;
    slide.style.opacity = opacity.toFixed(3);
    slide.style.transform = `translateX(-50%) rotateY(${slideDeg}deg) translateZ(${R}px) scale(${scale.toFixed(3)})`;
  });
}

function go(piece, idx) {
  const prev = st[piece];
  st[piece] = ((idx % N) + N) % N;
  let d = st[piece] - prev;
  if (d >  N / 2) d -= N;
  if (d < -N / 2) d += N;
  const startAng = ang[piece];
  const endAng   = ang[piece] - d * (360 / N);
  ang[piece] = endAng;
  const start = performance.now();
  const duration = 650;
  const ring = document.getElementById('ring-' + piece);
  function frame(now) {
    const t = Math.min((now - start) / duration, 1);
    const ease = t < 0.5 ? 2*t*t : -1+(4-2*t)*t;
    const cur = startAng + (endAng - startAng) * ease;
    ring.style.transform = `rotateY(${cur}deg)`;
    // update per-slide opacities using current ring angle
    const slides = ring.querySelectorAll('.rslide');
    slides.forEach((slide, i) => {
      const slideDeg = (360 / N) * i;
      let eff = (slideDeg + cur) % 360;
      if (eff < 0) eff += 360;
      const cos = Math.cos(eff * Math.PI / 180);
      const opacity = 0.15 + (cos + 1) / 2 * 0.85;
      const scale = 0.82 + (cos + 1) / 2 * 0.18;
      slide.style.opacity = opacity.toFixed(3);
      slide.style.transform = `translateX(-50%) rotateY(${slideDeg}deg) translateZ(${R}px) scale(${scale.toFixed(3)})`;
    });
    if (t < 1) requestAnimationFrame(frame);
  }
  requestAnimationFrame(frame);
}

function next(p){go(p,st[p]+1)}
function prev(p){go(p,st[p]-1)}

['tie','jacket','pants'].forEach(p => { build(p); updateOpacities(p); });

// Swipe
['tie','jacket','pants'].forEach(piece=>{
  const row=document.querySelector('#ring-'+piece).closest('.piece-row');
  let sx=0,drag=false;
  let sy=0;
  row.addEventListener('touchstart',e=>{sx=e.touches[0].clientX;sy=e.touches[0].clientY},{passive:true});
  row.addEventListener('touchmove',e=>{const dx=e.touches[0].clientX-sx;const dy=e.touches[0].clientY-sy;if(Math.abs(dx)>Math.abs(dy))e.preventDefault();},{passive:false});
  row.addEventListener('touchend',e=>{const dx=sx-e.changedTouches[0].clientX;if(Math.abs(dx)>30)dx>0?next(piece):prev(piece)});
  row.addEventListener('mousedown',e=>{drag=true;sx=e.clientX});
  row.addEventListener('mouseup',e=>{if(!drag)return;drag=false;const dx=sx-e.clientX;if(Math.abs(dx)>20)dx>0?next(piece):prev(piece)});
  row.addEventListener('mouseleave',()=>drag=false);
});

// Swatches couleur
document.querySelectorAll('.swatch').forEach(btn=>{
  btn.addEventListener('click',()=>{
    document.querySelectorAll('.swatch').forEach(s=>s.classList.remove('active'));
    btn.classList.add('active');
  });
});

// Formulaire
function handleSubmit(){
  const p=document.getElementById('prenom').value.trim();
  const n=document.getElementById('nom').value.trim();
  const e=document.getElementById('email').value.trim();
  const r=document.getElementById('rgpd').checked;
  if(!p||!n||!e){alert('Veuillez remplir tous les champs.');return}
  if(!e.includes('@')){alert('E-mail invalide.');return}
  if(!r){alert('Veuillez accepter les conditions.');return}
  document.getElementById('inscriptionForm').style.display='none';
  document.getElementById('confirmMsg').style.display='block';
}
